// DownloadedDocument DownloadedDocument downloaded non-HTML document (PDF, DOCX, image, code file, etc.).

// When the crawler encounters non-HTML content and `download_documents` is
// enabled, it downloads the raw bytes and populates this struct instead of
// skipping the resource.
type DownloadedDocument struct {
	// The URL the document was fetched from.
	URL string `json:"url"`
	// The MIME type from the Content-Type header.
	MimeType string `json:"mime_type"`
	// Raw document bytes. Skipped during JSON serialization.
	Content []byte `json:"content"`
	// Size of the document in bytes.
	Size uint `json:"size"`
	// Filename extracted from Content-Disposition or URL path.
	Filename *string `json:"filename,omitempty"`
	// SHA-256 hex digest of the content.
	ContentHash string `json:"content_hash"`
	// Selected response headers.
	Headers map[string]string `json:"headers,omitempty"`
}

// MarshalJSON serializes `[]byte` fields as a JSON array of integers (the format
// Rust's serde `Vec<u8>` deserializer expects) instead of Go's default base64 string.
func (v DownloadedDocument) MarshalJSON() ([]byte, error) {
	// Explicit shadow struct listing every field — embedding the original
	// would cause both base64-string and int-array entries for the same JSON
	// key. Bytes fields rendered as `[]int`; everything else copied verbatim.
	aux := struct {
		URL         string            `json:"url"`
		MimeType    string            `json:"mime_type"`
		Content     []int             `json:"content"`
		Size        uint              `json:"size"`
		Filename    *string           `json:"filename,omitempty"`
		ContentHash string            `json:"content_hash"`
		Headers     map[string]string `json:"headers,omitempty"`
	}{}
	aux.URL = v.URL
	aux.MimeType = v.MimeType
	aux.Content = make([]int, len(v.Content))
	for i, b := range v.Content {
		aux.Content[i] = int(b)
	}
	aux.Size = v.Size
	aux.Filename = v.Filename
	aux.ContentHash = v.ContentHash
	aux.Headers = v.Headers
	return json.Marshal(aux)
}

